import React, { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [categoriaActual, setCategoriaActual] = useState({
    CategoriaID: null,
    Nombre: "",
  });
  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [busqueda, setBusqueda] = useState("");

  const navigate = useNavigate();

  // Paginación
  const [paginaActual, setPaginaActual] = useState(1);
  const categoriasPorPagina = 6;

  useEffect(() => {
    obtenerCategorias();
  }, []);

  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("❌ Error al obtener categorías:", error);
    }
  };

  const handleChange = (e) => {
    setCategoriaActual({
      ...categoriaActual,
      [e.target.name]: e.target.value,
    });
  };

  const abrirModalAgregar = () => {
    setCategoriaActual({ CategoriaID: null, Nombre: "" });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalEditar = (categoria) => {
    setCategoriaActual(categoria);
    setModoEdicion(true);
    setShowModal(true);
  };

  const guardarCategoria = async (e) => {
    e.preventDefault();
    try {
      if (modoEdicion) {
        await axios.put(
          `http://localhost:5000/api/categorias/${categoriaActual.CategoriaID}`,
          categoriaActual
        );
      } else {
        await axios.post(
          "http://localhost:5000/api/categorias",
          categoriaActual
        );
      }
      setShowModal(false);
      obtenerCategorias();
    } catch (error) {
      console.error("❌ Error al guardar categoría:", error);
    }
  };

  const eliminarCategoria = async (id) => {
    if (window.confirm("¿Seguro que deseas eliminar esta categoría?")) {
      try {
        await axios.delete(`http://localhost:5000/api/categorias/${id}`);
        obtenerCategorias();
      } catch (error) {
        console.error("❌ Error al eliminar categoría:", error);
      }
    }
  };

  // 🔎 Filtrado seguro
  const categoriasFiltradas = categorias.filter((c) =>
    (c.Nombre || "").toLowerCase().includes(busqueda.toLowerCase())
  );

  // 📄 Paginación
  const totalPaginas = Math.ceil(
    categoriasFiltradas.length / categoriasPorPagina
  );
  const indiceInicio = (paginaActual - 1) * categoriasPorPagina;
  const categoriasPaginadas = categoriasFiltradas.slice(
    indiceInicio,
    indiceInicio + categoriasPorPagina
  );

  return (
    <div className="container mt-5">
      {/* Buscador */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <input
          type="text"
          className="form-control w-50"
          placeholder="Buscar categoría..."
          value={busqueda}
          onChange={(e) => {
            setBusqueda(e.target.value);
            setPaginaActual(1);
          }}
        />
        <button className="btn btn-success btn-lg" onClick={abrirModalAgregar}>
          ➕ Agregar Categoría
        </button>
      </div>

      {/* Cards */}
      <div className="row">
        {categoriasPaginadas.map((cat) => (
          <div key={cat.CategoriaID} className="col-md-4 mb-4">
            <div
              className="card shadow-sm h-100"
              style={{ cursor: "pointer" }}
              onClick={() => navigate(`/categorias/${cat.CategoriaID}`)}
            >
              <div className="card-body d-flex flex-column justify-content-between">
                <h5 className="card-title text-center">{cat.Nombre}</h5>

                <div className="d-flex justify-content-between mt-3">
                  <button
                    className="btn btn-warning btn-sm"
                    onClick={(e) => {
                      e.stopPropagation();
                      abrirModalEditar(cat);
                    }}
                  >
                    ✏️ Editar
                  </button>
                  <button
                    className="btn btn-danger btn-sm"
                    onClick={(e) => {
                      e.stopPropagation();
                      eliminarCategoria(cat.CategoriaID);
                    }}
                  >
                    🗑️ Eliminar
                  </button>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Modal */}
      {showModal && (
        <div
          className="modal fade show"
          style={{ display: "block", backgroundColor: "rgba(0,0,0,0.6)" }}
        >
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content p-4">
              <div className="modal-header">
                <h5 className="modal-title">
                  {modoEdicion ? "Editar Categoría" : "Nueva Categoría"}
                </h5>
                <button
                  className="btn-close"
                  onClick={() => setShowModal(false)}
                ></button>
              </div>

              <form onSubmit={guardarCategoria}>
                <div className="modal-body">
                  <label className="form-label">Nombre</label>
                  <input
                    type="text"
                    name="Nombre"
                    className="form-control"
                    value={categoriaActual.Nombre}
                    onChange={handleChange}
                    required
                  />
                </div>

                <div className="modal-footer">
                  <button
                    type="button"
                    className="btn btn-secondary"
                    onClick={() => setShowModal(false)}
                  >
                    Cancelar
                  </button>
                  <button type="submit" className="btn btn-primary">
                    Guardar
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
